    private BlockDataLookup() {
    }

    public static BlockData lookup(int id) {
        int index = Arrays.binarySearch(LOOKUP_TABLE, new Info(id, null));
        index = index < 0 ? (-index - 2) : index;
        if (index < 0) {
            throw new IllegalArgumentException("id smaller than first entry: " + id);
        }
        BlockData base = LOOKUP_TABLE[index].factory.get();
        base.load(id);
        return base;
    }

    private static class Info implements Comparable<Info> {
        private final int id;

        private final Supplier<BlockData> factory;

        private Info(int id, Supplier<BlockData> factory) {
            this.id = id;
            this.factory = factory;
        }

        @Override
        public int compareTo(Info other) {
            return Integer.compare(id, other.id);
        }
    }
